import{_ as r,o as t,c as i,ag as o}from"./chunks/framework.ETe_P6d1.js";const a="/kaiping-reports/assets/1.2HgD-IdE.jpg",s="/kaiping-reports/assets/2.DL6ixw73.jpg",p="/kaiping-reports/assets/3.CIA8nS1p.jpg",h="/kaiping-reports/assets/4.DEpibix0.jpg",l="/kaiping-reports/assets/5.DijmfNjI.jpg",n="/kaiping-reports/assets/6.Bac0Y6_h.jpg",c="/kaiping-reports/assets/7.Ds3SKXPK.jpg",d="/kaiping-reports/assets/8.i3_x7Cvt.jpg",_="/kaiping-reports/assets/9.CKZO9O19.jpg",P=JSON.parse('{"title":"专业调研报告内容：","description":"","frontmatter":{"title":"专业调研报告内容："},"headers":[],"relativePath":"reports/陈杨文/陈杨文_陈杨文_调研报告.md","filePath":"reports/陈杨文/陈杨文_陈杨文_调研报告.md"}'),m={name:"reports/陈杨文/陈杨文_陈杨文_调研报告.md"};function u(b,e,q,g,k,f){return t(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="专业调研报告内容" tabindex="-1">专业调研报告内容： <a class="header-anchor" href="#专业调研报告内容" aria-label="Permalink to &quot;专业调研报告内容：&quot;">​</a></h1><h1 id="组名" tabindex="-1">组名： <a class="header-anchor" href="#组名" aria-label="Permalink to &quot;组名：&quot;">​</a></h1><h1 id="成员" tabindex="-1">成员： <a class="header-anchor" href="#成员" aria-label="Permalink to &quot;成员：&quot;">​</a></h1><h1 id="考察时间" tabindex="-1">考察时间： <a class="header-anchor" href="#考察时间" aria-label="Permalink to &quot;考察时间：&quot;">​</a></h1><h1 id="考察地点" tabindex="-1">考察地点： <a class="header-anchor" href="#考察地点" aria-label="Permalink to &quot;考察地点：&quot;">​</a></h1><h1 id="一、调研概况与选取理由" tabindex="-1">一、调研概况与选取理由 <a class="header-anchor" href="#一、调研概况与选取理由" aria-label="Permalink to &quot;一、调研概况与选取理由&quot;">​</a></h1><p>本次考察以开平近代建筑为核心对象，选取立园、自力村碉楼群、赤坎古镇骑楼街、仓东村传统村落及塘口墟近代商业建筑作为重点调研点位。上述地点集中呈现碉楼、华侨园林、骑楼、传统民居、旧墟公共建筑等典型类型，完整覆盖近代侨乡建筑的营造特征、文化内涵与功能形态，是研究中西建筑文化融合、地域适应性设计、传统智慧现代转译的优质样本。本次调研旨在通过现场观察、图解记录、维度分析，系统解读开平近代建筑的空间逻辑、构造策略、装饰语言与场所精神，完成建筑史课程调研任务，并提炼可应用于现代设计的营造智慧。</p><h1 id="二、建筑类型与整体特征" tabindex="-1">二、建筑类型与整体特征 <a class="header-anchor" href="#二、建筑类型与整体特征" aria-label="Permalink to &quot;二、建筑类型与整体特征&quot;">​</a></h1><p>开平近代建筑形成于20世纪初至中叶，以华侨归国建设为主要动力，呈现中西<strong>合璧、功能复合、地域适配的鲜明特征。</strong></p><h1 id="_1-华侨园林" tabindex="-1">1．华侨园林： <a class="header-anchor" href="#_1-华侨园林" aria-label="Permalink to &quot;1．华侨园林：&quot;">​</a></h1><h1 id="_2-碉楼建筑" tabindex="-1">2．碉楼建筑： <a class="header-anchor" href="#_2-碉楼建筑" aria-label="Permalink to &quot;2．碉楼建筑：&quot;">​</a></h1><h1 id="_3-骑楼建筑" tabindex="-1">3．骑楼建筑： <a class="header-anchor" href="#_3-骑楼建筑" aria-label="Permalink to &quot;3．骑楼建筑：&quot;">​</a></h1><h1 id="_4-传统村落与旧墟建筑" tabindex="-1">4．传统村落与旧墟建筑： <a class="header-anchor" href="#_4-传统村落与旧墟建筑" aria-label="Permalink to &quot;4．传统村落与旧墟建筑：&quot;">​</a></h1><p>整体而言，开平近代建筑既坚守岭南地域营造逻辑，又大胆吸收西方形式、材料与技术，形成独一无二的侨乡建筑体系。</p><p><img src="'+a+'" alt="1"></p><p><img src="'+s+'" alt="2"></p><p><img src="'+p+'" alt="3"></p><h1 id="三、空间类型与形态分析" tabindex="-1">三、空间类型与形态分析 <a class="header-anchor" href="#三、空间类型与形态分析" aria-label="Permalink to &quot;三、空间类型与形态分析&quot;">​</a></h1><p>空间布局以实用功能为主、礼制秩序为辅，突破传统封闭合院，呈现多元形态。</p><p>立园采用前庭后院、中西分区的布局模式，入口序列层层递进，院落开敞通透，以水景、绿化连接中式亭台与西式别墅，形成园宅相融的空间格局。主体别墅为对称式平面，设置客厅、卧室、书房与露台，空间开放明亮，区别于传统民居的内向性。</p><p>自力村碉楼以垂直分层为核心特征，平面多为方形，底层用作储物与公共活动，中层为居住空间，顶层为防御瞭望平台。碉楼与周边三合院民居松散布局，形成“防御核心＋分散居住”的村落肌理，顺应地形且便于快速集结避险。</p><p><img src="'+h+'" alt="4"></p><p>赤坎骑楼为水平联排形态，底层连续商铺，上层居住，外廊作为公共步行空间，实现街道与建筑的无缝衔接。平面规整、流线清晰，既满足商业经营需求，又适配岭南多雨湿热气候。</p><h1 id="整体空间策略体现出功能优先、灵活适配、层" tabindex="-1">整体空间策略体现出功能优先、灵活适配、层 <a class="header-anchor" href="#整体空间策略体现出功能优先、灵活适配、层" aria-label="Permalink to &quot;整体空间策略体现出功能优先、灵活适配、层&quot;">​</a></h1><h1 id="四、建造材料与构造技术" tabindex="-1">四、建造材料与构造技术 <a class="header-anchor" href="#四、建造材料与构造技术" aria-label="Permalink to &quot;四、建造材料与构造技术&quot;">​</a></h1><p>材料与构造是开平近代建筑最具价值的部分，实现传统工艺与现代技术的高效融合。</p><p>结构上，碉楼以钢筋混凝土现浇为主，梁柱一体、整体性强，满足防御与耐久要求；传统民居与园林建筑沿用砖木结构，木梁架承重、青砖砌筑，成本低、施工便捷；骑楼多采用砖混结构，砖墙承重、混凝土楼板，兼顾安全与经济性。</p><p>立面材料以本土青砖、红砖为基底，搭配水泥抹灰、马赛克瓷砖、彩色玻璃等近代工业材料。构造做法融合传统灰缝砌筑、木作榫卯与现代现浇、预制安装技术，施工痕迹清晰可见，既保证坚固耐用，又提升建造效率。这种本土材料＋外来技术的策略，高度适配侨乡的资源条件与使用需求。</p><p><img src="'+l+'" alt="5"></p><h1 id="五、装饰符号与文化表达" tabindex="-1">五、装饰符号与文化表达 <a class="header-anchor" href="#五、装饰符号与文化表达" aria-label="Permalink to &quot;五、装饰符号与文化表达&quot;">​</a></h1><p>装饰以中西拼贴、寓意吉祥为特点，是华侨文化认同的物质表达。</p><p>中式元素以灰塑、砖雕、木雕为主，题材多为龙凤、花鸟、吉祥文字，多用于屋脊、门窗、梁架等部位，延续岭南传统审美。西式元素以罗马柱、拱券、山花、涡卷纹为主，用于立面主体、入口、阳台等醒目位置，体现对西方文明的接纳。</p><p>立园是典型代表：中式亭台做灰塑花鸟，西式别墅设罗马柱与三角山花，门窗融合中式雕花与西式拱券。碉楼装饰简洁克制，以西式线条与中式文字点缀，强调防御优先。骑楼则以西式山花搭配中式牌匾，商业气息与文化内涵并存。色彩以青、灰、红为主，低调稳重，契合华侨务实内敛的气质。</p><p><img src="'+n+'" alt="6"></p><p><img src="'+c+'" alt="7"></p><p><img src="'+d+'" alt="8"></p><h1 id="六、功能布局与使用方式" tabindex="-1">六、功能布局与使用方式 <a class="header-anchor" href="#六、功能布局与使用方式" aria-label="Permalink to &quot;六、功能布局与使用方式&quot;">​</a></h1><p>建筑功能围绕防御、居住、商业、社交展开，并随时代完成适应性转化。</p><p>碉楼以防御为核心，平时居住、储物，战乱时提供庇护；民居满足家庭日常起居；</p><p>立园集居住、会客、休闲于一体；骑楼实现下商上住、商住混合。</p><p>现代使用已发生显著更新：立园成为文旅景区与文化展示场所；自力村碉楼以观光为主，部分民居改为民宿；塘口墟旧建筑改造为先锋书店，植入文化阅读功能；赤坎古镇经整体修缮，成为文旅商业街区。功能更新延续了建筑生命力，实现历史价值与现代价值的统一。</p><p><img src="'+_+'" alt="9"></p><h1 id="七、环境关系与场所精神" tabindex="-1">七、环境关系与场所精神 <a class="header-anchor" href="#七、环境关系与场所精神" aria-label="Permalink to &quot;七、环境关系与场所精神&quot;">​</a></h1><h3 id="开平近代建筑高度顺应自然、融入聚落-形成强烈的场所归属感。" tabindex="-1">开平近代建筑高度顺应自然、融入聚落，形成强烈的场所归属感。 <a class="header-anchor" href="#开平近代建筑高度顺应自然、融入聚落-形成强烈的场所归属感。" aria-label="Permalink to &quot;开平近代建筑高度顺应自然、融入聚落，形成强烈的场所归属感。&quot;">​</a></h3><p>建筑多坐北朝南，利于采光通风；赤坎骑楼临江而建，依托水路形成商业活力；立园引水造景，建筑与自然共生。村落层面，碉楼散点布局形成防御网络，又不破坏原有肌理；仓东村、塘口墟保留传统街巷尺度，生活气息浓厚。</p><p>这些建筑承载着华侨的奋斗史与思乡情，坚固的碉楼象征坚韧，中西融合的形态象征包容，院落与街巷承载着乡土生活记忆，构成不可复制的侨乡场所精神。</p><p><img src="'+a+'" alt="1"></p><p><img src="'+a+'" alt="1"></p><h1 id="八、尺度与人体感知" tabindex="-1">八、尺度与人体感知 <a class="header-anchor" href="#八、尺度与人体感知" aria-label="Permalink to &quot;八、尺度与人体感知&quot;">​</a></h1><p>建筑尺度以人体工学为基础，兼顾实用功能与空间感受。</p><p>碉楼3-5层，高耸挺拔，具有标志性与安全感；骑楼2-3层，街道尺度宜人，无压抑感；民居与园林建筑1-2层，贴近日常使用。门窗、廊道、院落均按人体尺度设计，行走、停留、观景舒适自然。空间通过高低、开合、宽窄的对比，营造出安全、亲切、富有层次的体验。</p><h1 id="九、现代改造与利用启示" tabindex="-1">九、现代改造与利用启示 <a class="header-anchor" href="#九、现代改造与利用启示" aria-label="Permalink to &quot;九、现代改造与利用启示&quot;">​</a></h1><p><img src="'+a+'" alt="1"></p><p>开平近代建筑的保护与更新遵循保护优先、适度更新、功能适配原则。</p><p>立园以原貌保护为主，局部修缮；自力村以最小干预维持历史信息；塘口墟采用微更新，保留外观、更新内部；赤坎古镇整体修复风貌，升级设施以适配文旅。其启示在于：保留历史特征、适度植入新功能、新旧材料协调、环境整体统一，让历史建筑活在当代生活中。</p><p><img src="'+a+'" alt="1"></p><p><img src="'+a+'" alt="1"></p><p><img src="'+a+'" alt="1"></p><h1 id="十、现存问题与优化建议" tabindex="-1">十、现存问题与优化建议 <a class="header-anchor" href="#十、现存问题与优化建议" aria-label="Permalink to &quot;十、现存问题与优化建议&quot;">​</a></h1><h1 id="现存问题" tabindex="-1">现存问题： <a class="header-anchor" href="#现存问题" aria-label="Permalink to &quot;现存问题：&quot;">​</a></h1><h1 id="优化建议" tabindex="-1">优化建议： <a class="header-anchor" href="#优化建议" aria-label="Permalink to &quot;优化建议：&quot;">​</a></h1><h1 id="十一、调研总结" tabindex="-1">十一、调研总结 <a class="header-anchor" href="#十一、调研总结" aria-label="Permalink to &quot;十一、调研总结&quot;">​</a></h1><p>开平近代建筑是近代侨乡文化与建筑技术融合的典范，在空间、构造、装饰、功能、环境等方面均展现出高度智慧。其<strong>中西兼容、功能务实、地域适应、耐久安全的设计逻辑，不</strong>是历史遗产，更是现代设计的“活教材”。</p><p>通过本次考察，我们掌握了现场观察、快速记录、维度分析、团队协作的调研方法，深刻理解了历史建筑的价值不仅在于形式，更在于其应对气候、社会、生活的智慧。未来可将开平近代建筑的空间原型、构造策略、装饰符号、环境理念转译应用于现代设计，让侨乡营造智慧在当代持续传承与创新。</p><p><img src="'+a+'" alt="1"></p>',65)])])}const j=r(m,[["render",u]]);export{P as __pageData,j as default};
